// Zapier Formatter (Python): Format phone number to E.164 standard for Twilio
import re
raw_phone = input_data.get('phone', '')
digits = re.sub(r'\D', '', raw_phone)
if len(digits) == 10:
    formatted = f"+1{digits}"
else:
    formatted = f"+{digits}"
return {'formatted_phone': formatted}

