// Airtable Automation Script: Validate Dropbox URL before sending
let table = base.getTable("Properties");
let record = await input.recordAsync();

if (!record.getCellValueAsString("Delivery Folder").includes("dropbox.com")) {
    console.warn("Invalid delivery link. Halting automation.");
} else {
    await table.updateRecordAsync(record.id, {
        "Status": {name: "Delivered & Emailed"}
    });
}
